previewCss:
.darma-loader-darma-custom-297 {
  width: fit-content;
  font-size: 34px;
  font-family: system-ui,sans-serif;
  font-weight: bold;
  text-transform: uppercase;
  color: #0000;
  -webkit-text-stroke: 1px var(--loader-color, #e11d48);
  background:
    radial-gradient(0.71em at 50% 1em,var(--loader-color, #e11d48) 99%,#0000 101%) calc(50% - 1em) 1em/2em 200% repeat-x text,
    radial-gradient(0.71em at 50% -0.5em,#0000 99%,var(--loader-color, #e11d48) 101%) 50% 1.5em/2em 200% repeat-x text;
  animation: 
    darma-loader-darma-custom-297-l10-0 .8s linear infinite alternate,
    darma-loader-darma-custom-297-l10-1  4s linear infinite;
}
.darma-loader-darma-custom-297:before {
  content: "Loading";
}
@keyframes darma-loader-darma-custom-297-l10-0 {
  to {background-position-x: 50%,calc(50% + 1em)}
}
@keyframes darma-loader-darma-custom-297-l10-1 {
  to {background-position-y: -.5em,0}
}

